/**
 * Called when the plugin starts. Sends the 'Magic Packet'
 * to switch the keyboard MCU into streaming/sync mode.
 */
export function Initialize() {
    // Send Magic Packet (Command 0x10) to put keyboard into streaming mode
    let magic = new Array(65).fill(0);
    magic[0] = 0x00; // Report ID
    magic[1] = 0xaa; // Wake command header
    magic[2] = 0x10; // Sub-command to enable Aurora/Streaming mode
    device.write(magic, 65);
}

/**
 * Main execution loop.
 * Called every time SignalRGB detects a change in the canvas or properties
 * to update colors on the keyboard.
 */
export function Render() {
    sendColors();
}

/**
 * Called when the system is shutting down.
 * @param {boolean} SystemSuspending - True if the PC is entering sleep/hibernate.
 */
export function Shutdown(SystemSuspending) {
    if(SystemSuspending){
        sendColors("#000000"); // Turn off LEDs immediately when system is going to sleep/hibernate
    } else {
        // Switch to the user-defined shutdown color
        sendColors(shutdownColor);
    }
}

/**
 * Main color processing function. Fetches colors from SignalRGB,
 * converts them to the device-specific format, and dispatches them via USB.
 * @param {string} [overrideColor] - Optional hex color to override the entire device (used for Shutdown/Forced modes).
 */
function sendColors(overrideColor) {
    let ledData = [];

    // Step 1: Process each of the 82 logical LEDs defined in the mapping.
    for (var idx = 0; idx < 82; idx++) {
        let iPxX = vLedPositions[idx][0];
        let iPxY = vLedPositions[idx][1];
        var color;

        // Logic to determine the color source:
        // 1. External override (e.g., during Shutdown)
        // 2. Forced color mode (User-selected static color)
        // 3. Canvas color (Standard SignalRGB effect streaming)
        if(overrideColor){
            color = hexToRgb(overrideColor);
        } else if (LightingMode === "Forced") {
            color = hexToRgb(forcedColor);
        } else {
            color = device.color(iPxX, iPxY);
        }

        // Step 2: Protocol Conversion (RGB888 to RGB565).
        // The keyboard MCU uses 16-bit color depth to save USB bandwidth.
        // Red (5 bits), Green (6 bits), Blue (5 bits).
        let r5 = (color[0] >> 3) & 0x1F;
        let g6 = (color[1] >> 2) & 0x3F;
        let b5 = (color[2] >> 3) & 0x1F;

        // Combine components into a single 16-bit integer (RGB565 format).
        let rgb565 = (r5 << 11) | (g6 << 5) | b5;

        // Step 3: Buffer preparation.
        // HID data is sent in bytes. We split the 16-bit color into 2 bytes.
        // The device expects Little Endian format (LSB first, then MSB).
        // LSB: Least Significant Byte, MSB: Most Significant Byte.
        ledData.push(rgb565 & 0xFF); // LSB
        ledData.push((rgb565 >> 8) & 0xFF); // MSB
    }

    // Step 4: Transmission Dispatch.
    // The total payload is 164 bytes (82 LEDs * 2 bytes).
    // Due to HID report limitations, we split the payload into 3 consecutive chunks.
    // sendChunk parameters: (Byte Offset, Number of Bytes, Full Data Array)
    sendChunk(0, 56, ledData); // First chunk: bytes 0-55
    sendChunk(56, 56, ledData); // Second chunk: bytes 56-111
    sendChunk(112, 52, ledData); // Final chunk: bytes 112-163
}

/**
 * Encapsulates LED data into a 65-byte HID report and sends it to the device.
 * @param {number} offset - The starting position in the full LED data array.
 * @param {number} length - Number of bytes to send in this specific chunk.
 * @param {array} payload - The complete array of RGB565 color data.
 */
function sendChunk(offset, length, payload) {
    // Initialize a 65-byte array filled with zeros (standard HID report size).
    let packet = new Array(65).fill(0);

    packet[0] = 0x00; // Report ID
    packet[1] = 0xaa; // General command
    packet[2] = 0x2e; // LED Streaming/Update
    packet[3] = offset & 0xFF;         // Offset Low Byte
    packet[4] = (offset >> 8) & 0xFF;  // Offset High Byte
    packet[5] = length & 0xFF;         // Data Length Low Byte
    packet[6] = (length >> 8) & 0xFF;  // Data Length High Byte

    // Payload data starts from byte 9 of the HID report.
    // Bytes 7 and 8 are padding and remain 0x00.
    for(let i = 0; i < length; i++) {
        packet[9 + i] = payload[offset + i];
    }

    // Write the finalized 65-byte packet to the keyboard.
    device.write(packet, 65);
}

/**
 * Parses a Hexadecimal color string into an RGB array.
 * @param {string} hex - Color in hex format (e.g., "#FF0000").
 * @returns {array} - An array containing [Red, Green, Blue] values (0-255).
 */
function hexToRgb(hex) {
    // Regex to split the hex string into 3 groups (R, G, B).
    let result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    let colors = [];
    // Convert base-16 strings to base-10 integers.
    colors[0] = parseInt(result[1], 16);
    colors[1] = parseInt(result[2], 16);
    colors[2] = parseInt(result[3], 16);
    return colors;
}

/**
 * Filters and validates the correct USB HID endpoint for LED communication.
 * @param {object} endpoint - The HID endpoint object provided by SignalRGB.
 * @returns {boolean} - True if the endpoint matches the custom vendor interface.
 */
export function Validate(endpoint) {
    // Interface 1 is the vendor-defined interface used for custom data (RGB/Macros).
    // Usage Page 0xff60 is the specific HID usage page defined by the manufacturer for LED streaming.
    // Standard interfaces (like Interface 0 for typing) are restricted by the OS.
    return endpoint.interface === 1 && endpoint.usage_page === 0xff60;
}

/** @returns {string} URL to an image to represent the device in the UI. */
export function ImageUrl() {
    // Png image converted to base64
    return "data:image/png;base64,";
}